import { useState, useEffect, useCallback } from 'react';
import { api, apiPost, apiPut, apiDelete } from '../utils/api';
import LoadingState from '../components/LoadingState';
import usePageTitle from '../hooks/usePageTitle';
import { tokens } from '../styles/tokens';
import { AURA_TIERS, AI_ADDON_PRICING, COMPUTE_PRICING } from '../config/pricing';
import s from './UserManagementPage.module.css';

const C = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, textPrimary: tokens.color.text, textSecondary: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};
const mono = tokens.font.mono;
const body = tokens.font.sans;

const ROLES = ['viewer', 'operator', 'admin'];
const ROLE_COLORS = { admin: '#EF4444', operator: '#F59E0B', viewer: '#60A5FA' };
const STATUS_COLORS = { active: '#22C55E', inactive: '#90A3AF', pending_approval: '#F59E0B', rejected: '#EF4444' };

const TIER_LABELS = { free: 'Free', explorer: 'Explorer', trader: 'Trader', pro: 'Pro', institutional: 'Institutional' };
const TIER_COLORS = { free: '#90A3AF', explorer: '#90A3AF', trader: '#60A5FA', pro: '#A78BFA', institutional: '#F59E0B' };
const GRANTABLE_TIERS = ['free', 'explorer', 'trader', 'pro', 'institutional'];

const AI_TIER_LABELS = { trial: 'Free Trial', basic: 'Basic', pro: 'Pro', enterprise: 'Enterprise' };
const AI_TIER_COLORS = { trial: '#90A3AF', basic: '#60A5FA', pro: '#A78BFA', enterprise: '#F59E0B' };
const AI_GRANTABLE_TIERS = ['trial', 'basic', 'pro', 'enterprise'];

const COMPUTE_TIER_LABELS = { local: 'Local (Free)', cloud_starter: 'Cloud Starter', cloud_pro: 'Cloud Pro', cloud_dedicated: 'Cloud Dedicated' };
const COMPUTE_TIER_COLORS = { local: '#90A3AF', cloud_starter: '#60A5FA', cloud_pro: '#A78BFA', cloud_dedicated: '#F59E0B' };
const COMPUTE_GRANTABLE_TIERS = ['local', 'cloud_starter', 'cloud_pro', 'cloud_dedicated'];

function RoleBadge({ role }) {
  const color = ROLE_COLORS[role] || '#90A3AF';
  return (
    <span className={s.roleBadge} style={{ background: color }}>
      {role}
    </span>
  );
}

function TierBadge({ tier, grantedBy }) {
  const color = TIER_COLORS[tier] || '#90A3AF';
  const label = TIER_LABELS[tier] || tier;
  return (
    <span className={s.tierBadgeWrap}>
      <span className={s.tierBadge} style={{ color, border: `1px solid ${color}44`, background: `${color}15` }}>
        {label}
      </span>
      {grantedBy && <span className={s.tierComp}>COMP</span>}
    </span>
  );
}

function StatusDot({ status }) {
  const color = STATUS_COLORS[status] || '#90A3AF';
  return (
    <span className={s.statusWrap}>
      <span className={s.statusDot} style={{
        background: color,
        boxShadow: status === 'active' ? `0 0 6px ${color}` : 'none',
      }} />
      <span className={s.statusText} style={{ color }}>{status}</span>
    </span>
  );
}

function ConfirmModal({ message, onConfirm, onCancel }) {
  return (
    <div className={s.modalOverlay} onClick={onCancel}>
      <div className={s.modalPanel} onClick={e => e.stopPropagation()}>
        <h3 className={s.modalTitle}>Confirm Action</h3>
        <p className={s.modalDesc}>{message}</p>
        <div className={s.modalActions}>
          <button onClick={onCancel} className={s.btnSecondary}>Cancel</button>
          <button onClick={onConfirm} className={s.btnDelete}>Delete</button>
        </div>
      </div>
    </div>
  );
}

function TierSelector({ tiers, labels, colors, prices, descs, selected, onSelect }) {
  return (
    <div className={s.tierList}>
      {tiers.map(tier => {
        const isSelected = selected === tier;
        const color = colors[tier];
        return (
          <div
            key={tier}
            onClick={() => onSelect(tier)}
            className={s.tierOption}
            style={{
              background: isSelected ? `${color}12` : undefined,
              borderColor: isSelected ? `${color}60` : undefined,
            }}
          >
            <div className={s.tierOptionRow}>
              <div className={s.tierOptionLeft}>
                <div className={s.tierRadio} style={{
                  borderColor: isSelected ? color : undefined,
                  background: isSelected ? color : undefined,
                }}>
                  {isSelected && <div className={s.tierRadioDot} />}
                </div>
                <span className={s.tierName}>{labels[tier]}</span>
              </div>
              <span className={s.tierPrice} style={{ color }}>{prices[tier]}/mo</span>
            </div>
            <div className={s.tierDesc}>{descs[tier]}</div>
          </div>
        );
      })}
    </div>
  );
}

function GrantAccessModal({ user, subs, onGrant, onClose }) {
  const [tab, setTab] = useState('platform');
  const [selectedPlatform, setSelectedPlatform] = useState(subs.platform?.tier || 'trader');
  const [selectedAI, setSelectedAI] = useState(subs.ai?.tier || 'basic');
  const [selectedCompute, setSelectedCompute] = useState(subs.compute?.tier || 'cloud_starter');
  const [saving, setSaving] = useState(false);

  const tabs = [
    { key: 'platform', label: 'Platform', color: '#22C55E' },
    { key: 'ai', label: 'AI', color: '#60A5FA' },
    { key: 'compute', label: 'Compute', color: '#A78BFA' },
  ];

  const platformPrices = Object.fromEntries(
    Object.entries(AURA_TIERS).map(([k, v]) => [k, v.price === 0 ? '$0' : `$${v.price}`])
  );
  const platformDescs = {
    free: 'Paper trading, 1 bot, 10 strategies, US only',
    trader: 'Live trading, 1 bot, all strategies, US',
    pro: 'Live trading, unlimited bots, all strategies + ML, 47 brokers, all regions',
    institutional: 'Unlimited everything, priority support',
  };

  const aiPrices = Object.fromEntries(
    Object.entries(AI_ADDON_PRICING).map(([k, v]) => [k, v.price === 0 ? '$0' : `$${v.price}`])
  );
  const aiDescs = {
    trial: '100K tokens/mo, Haiku only, 14-day trial',
    basic: '500K tokens/mo, Haiku model',
    pro: '2M tokens/mo, Haiku + Sonnet, deep analysis',
    enterprise: '10M tokens/mo, all models, priority queue',
  };

  const computePrices = Object.fromEntries(
    Object.entries(COMPUTE_PRICING).map(([k, v]) => [k, v.price === 0 ? '$0' : `$${v.price}`])
  );
  const computeDescs = {
    local: 'Own hardware only, register local workers',
    cloud_starter: '50 hrs/mo, 8 workers, cloud backtest + optimize',
    cloud_pro: '200 hrs/mo, 32 workers, ML training, priority queue',
    cloud_dedicated: 'Unlimited, 64 workers, GPU, dedicated instance, SLA',
  };

  const handleGrant = async () => {
    setSaving(true);
    const tierMap = { platform: selectedPlatform, ai: selectedAI, compute: selectedCompute };
    await onGrant(user.id, tab, tierMap[tab]);
    setSaving(false);
  };

  const currentSub = subs[tab];
  const currentTierLabel = tab === 'platform' ? TIER_LABELS[currentSub?.tier] || 'Free'
    : tab === 'ai' ? AI_TIER_LABELS[currentSub?.tier] || 'None'
    : COMPUTE_TIER_LABELS[currentSub?.tier] || 'None';

  return (
    <div className={s.modalOverlay} onClick={onClose}>
      <div className={s.modalPanelWide} onClick={e => e.stopPropagation()}>
        <h3 className={s.modalTitleGrant}>Manage Tiers</h3>
        <p className={s.modalDescGrant}>
          Set subscription tiers for <span className={s.modalUsername}>{user.username}</span> ({user.display_name}).
          Admin grants override billing — no Stripe charge.
        </p>

        {/* Tab bar */}
        <div className={s.grantTabBar}>
          {tabs.map(t => (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className={s.grantTab}
              style={{
                background: tab === t.key ? `${t.color}20` : undefined,
                color: tab === t.key ? t.color : undefined,
                borderBottomColor: tab === t.key ? t.color : undefined,
              }}
            >
              {t.label}
            </button>
          ))}
        </div>

        {/* Current status */}
        <div className={s.currentTierBox}>
          <div className={s.currentTierLabel}>Current {tab} Tier</div>
          <span className={s.currentTierValue}>{currentTierLabel}</span>
          {currentSub?.granted_by_username && (
            <span className={s.currentTierComp}>COMP (by {currentSub.granted_by_username})</span>
          )}
        </div>

        {/* Tier selectors */}
        {tab === 'platform' && (
          <TierSelector
            tiers={GRANTABLE_TIERS} labels={TIER_LABELS} colors={TIER_COLORS}
            prices={platformPrices} descs={platformDescs}
            selected={selectedPlatform} onSelect={setSelectedPlatform}
          />
        )}
        {tab === 'ai' && (
          <TierSelector
            tiers={AI_GRANTABLE_TIERS} labels={AI_TIER_LABELS} colors={AI_TIER_COLORS}
            prices={aiPrices} descs={aiDescs}
            selected={selectedAI} onSelect={setSelectedAI}
          />
        )}
        {tab === 'compute' && (
          <TierSelector
            tiers={COMPUTE_GRANTABLE_TIERS} labels={COMPUTE_TIER_LABELS} colors={COMPUTE_TIER_COLORS}
            prices={computePrices} descs={computeDescs}
            selected={selectedCompute} onSelect={setSelectedCompute}
          />
        )}

        {/* Actions */}
        <div className={s.modalActionsGrant}>
          <button onClick={onClose} className={s.btnSecondary}>Cancel</button>
          <button
            onClick={handleGrant}
            disabled={saving}
            className={s.btnApprove}
            style={{
              background: saving ? C.surface2 : undefined,
              cursor: saving ? 'wait' : undefined,
              opacity: saving ? 0.6 : undefined,
            }}
          >
            {saving ? 'Saving...' : 'Apply Tier'}
          </button>
        </div>
      </div>
    </div>
  );
}

export default function UserManagementPage() {
  usePageTitle('User Management');
  const [users, setUsers] = useState([]);
  const [subscriptions, setSubscriptions] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [showAddForm, setShowAddForm] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [editData, setEditData] = useState({});
  const [deleteConfirm, setDeleteConfirm] = useState(null);
  const [grantTarget, setGrantTarget] = useState(null);
  const [formData, setFormData] = useState({ username: '', display_name: '', role: 'viewer', email: '' });
  const [formError, setFormError] = useState(null);
  const [actionFeedback, setActionFeedback] = useState(null);

  const fetchUsers = useCallback(async () => {
    const data = await api('/users');
    if (data) {
      setUsers(data);
      setError(null);
    } else {
      setError('Failed to load users');
    }
    setLoading(false);
  }, []);

  const fetchSubscriptions = useCallback(async () => {
    const [platData, aiData, compData] = await Promise.all([
      api('/billing/admin/subscriptions'),
      api('/subscriptions/admin/subscriptions'),
      api('/compute/admin/subscriptions').catch(() => null),
    ]);
    const map = {};
    if (platData?.subscriptions) {
      for (const sub of platData.subscriptions) {
        if (!map[sub.user_id]) map[sub.user_id] = {};
        map[sub.user_id].platform = sub;
      }
    }
    if (aiData?.subscriptions) {
      for (const sub of aiData.subscriptions) {
        if (!map[sub.user_id]) map[sub.user_id] = {};
        map[sub.user_id].ai = sub;
      }
    }
    if (compData?.subscriptions) {
      for (const sub of compData.subscriptions) {
        if (!map[sub.user_id]) map[sub.user_id] = {};
        map[sub.user_id].compute = sub;
      }
    }
    setSubscriptions(map);
  }, []);

  useEffect(() => {
    fetchUsers();
    fetchSubscriptions();
  }, [fetchUsers, fetchSubscriptions]);

  const showFeedback = (msg, type = 'success') => {
    setActionFeedback({ msg, type });
    setTimeout(() => setActionFeedback(null), 3000);
  };

  const handleAddUser = async (e) => {
    e.preventDefault();
    setFormError(null);
    if (!formData.username.trim() || !formData.display_name.trim()) {
      setFormError('Username and display name are required');
      return;
    }
    const result = await apiPost('/users', formData);
    if (result && !result.detail) {
      setShowAddForm(false);
      setFormData({ username: '', display_name: '', role: 'viewer', email: '' });
      showFeedback(`User "${result.username}" created`);
      fetchUsers();
    } else {
      setFormError(result?.detail || 'Failed to create user');
    }
  };

  const startEdit = (user) => {
    setEditingId(user.id);
    setEditData({
      display_name: user.display_name,
      role: user.role,
      email: user.email || '',
      status: user.status,
    });
  };

  const cancelEdit = () => {
    setEditingId(null);
    setEditData({});
  };

  const saveEdit = async (userId) => {
    const result = await apiPut('/users/' + userId, editData);
    if (result && !result.detail) {
      setEditingId(null);
      setEditData({});
      showFeedback('User updated');
      fetchUsers();
    } else {
      showFeedback(result?.detail || 'Failed to update user', 'error');
    }
  };

  const toggleStatus = async (user) => {
    const newStatus = user.status === 'active' ? 'inactive' : 'active';
    const result = await apiPut('/users/' + user.id, { status: newStatus });
    if (result && !result.detail) {
      showFeedback(`${user.username} ${newStatus === 'active' ? 'activated' : 'deactivated'}`);
      fetchUsers();
    } else {
      showFeedback(result?.detail || 'Failed to toggle status', 'error');
    }
  };

  const handleDelete = async (user) => {
    const result = await apiDelete('/users/' + user.id);
    if (result && result.deleted) {
      setDeleteConfirm(null);
      showFeedback(`User "${user.username}" deleted`);
      fetchUsers();
    } else {
      setDeleteConfirm(null);
      showFeedback(result?.detail || 'Failed to delete user', 'error');
    }
  };

  const handleGrantAccess = async (userId, subType, tier) => {
    const endpoints = {
      platform: '/billing/admin/grant-access',
      ai: '/subscriptions/admin/grant-access',
      compute: '/compute/admin/grant-access',
    };
    const endpoint = endpoints[subType];
    if (!endpoint) { showFeedback('Unknown subscription type', 'error'); return; }

    const result = await apiPost(endpoint, { user_id: userId, tier });
    if (result && result.ok) {
      showFeedback(`${subType} ${tier} access granted`);
      setGrantTarget(null);
      fetchSubscriptions();
    } else {
      showFeedback(result?.detail || 'Failed to grant access', 'error');
    }
  };

  const formatDate = (ts) => {
    if (!ts) return '--';
    try {
      const d = new Date(ts);
      return d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) +
        ' ' + d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit' });
    } catch {
      return ts;
    }
  };

  const handleApprove = async (user) => {
    const result = await apiPost('/users/' + user.id + '/approve', {});
    if (result && !result.detail) {
      showFeedback(`${user.display_name} approved`);
      fetchUsers();
    } else {
      showFeedback(result?.detail || 'Failed to approve user', 'error');
    }
  };

  const handleReject = async (user) => {
    const result = await apiPost('/users/' + user.id + '/reject', {});
    if (result && !result.detail) {
      showFeedback(`${user.display_name} rejected`);
      fetchUsers();
    } else {
      showFeedback(result?.detail || 'Failed to reject user', 'error');
    }
  };

  const pendingUsers = users.filter(u => u.status === 'pending_approval');
  const nonPendingUsers = users.filter(u => u.status !== 'pending_approval');
  const adminCount = users.filter(u => u.role === 'admin').length;
  const activeCount = users.filter(u => u.status === 'active').length;

  return (
    <LoadingState loading={loading} error={error} empty={!users?.length} emptyMessage='No data available' type='table'>
      <div className={s.page}>
        {/* Header */}
        <div className={s.header}>
          <div>
            <h1 className={s.headerTitle}>User Management</h1>
            <p className={s.headerSub}>
              Manage user accounts, roles, platform access, and tier assignments
            </p>
          </div>
          <button onClick={() => { setShowAddForm(!showAddForm); setFormError(null); }} className={s.btnPrimary}>
            {showAddForm ? 'Cancel' : '+ Add User'}
          </button>
        </div>

        {/* Feedback Toast */}
        {actionFeedback && (
          <div className={s.toast} style={{
            background: actionFeedback.type === 'error' ? '#EF4444' : '#22C55E',
          }}>
            {actionFeedback.msg}
          </div>
        )}

        {/* Stats Summary */}
        <div className={s.statsGrid}>
          {[
            { label: 'Total Users', value: users.length, color: '#60A5FA' },
            { label: 'Active', value: activeCount, color: '#22C55E' },
            { label: 'Pending', value: pendingUsers.length, color: '#F59E0B' },
            { label: 'Admins', value: adminCount, color: '#EF4444' },
          ].map((stat, i) => (
            <div key={i} className={s.statCard}>
              <span className={s.statLabel}>{stat.label}</span>
              <span className={s.statValue} style={{ color: stat.color }}>{stat.value}</span>
            </div>
          ))}
        </div>

        {/* Add User Form */}
        {showAddForm && (
          <div className={s.panelCard}>
            <h3 className={s.panelTitle}>Create New User</h3>
            {formError && <div className={s.formError}>{formError}</div>}
            <form onSubmit={handleAddUser}>
              <div className={s.formGrid}>
                <div>
                  <label className={s.formLabel}>Username *</label>
                  <input
                    value={formData.username}
                    onChange={e => setFormData({ ...formData, username: e.target.value })}
                    placeholder="e.g. john"
                    className={s.formInput}
                    autoFocus
                  />
                </div>
                <div>
                  <label className={s.formLabel}>Display Name *</label>
                  <input
                    value={formData.display_name}
                    onChange={e => setFormData({ ...formData, display_name: e.target.value })}
                    placeholder="e.g. John Smith"
                    className={s.formInput}
                  />
                </div>
                <div>
                  <label className={s.formLabel}>Role</label>
                  <select
                    value={formData.role}
                    onChange={e => setFormData({ ...formData, role: e.target.value })}
                    className={s.formSelect}
                  >
                    {ROLES.map(r => (
                      <option key={r} value={r}>{r.charAt(0).toUpperCase() + r.slice(1)}</option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className={s.formLabel}>Email</label>
                  <input
                    value={formData.email}
                    onChange={e => setFormData({ ...formData, email: e.target.value })}
                    placeholder="user@example.com"
                    className={s.formInput}
                  />
                </div>
              </div>
              <div className={s.formBtns}>
                <button type="submit" className={s.btnPrimary}>Create User</button>
                <button type="button" onClick={() => setShowAddForm(false)} className={s.btnSecondary}>Cancel</button>
              </div>
            </form>
          </div>
        )}

        {/* Pending Approvals */}
        {pendingUsers.length > 0 && (
          <div className={s.panelCardPending}>
            <h3 className={s.panelTitlePending}>
              <span className={s.pendingDot} />
              Pending Approvals ({pendingUsers.length})
            </h3>
            <div className={s.pendingList}>
              {pendingUsers.map(user => (
                <div key={user.id} className={s.pendingItem}>
                  <div className={s.pendingInfo}>
                    <div className={s.pendingName}>
                      <span className={s.pendingDisplayName}>{user.display_name}</span>
                      <RoleBadge role={user.role} />
                    </div>
                    <div className={s.pendingEmail}>{user.email}</div>
                    <div className={s.pendingMeta}>
                      <span>User: {user.username}</span>
                      {user.ibkr_account && <span>IBKR: {user.ibkr_account}</span>}
                      <span>{formatDate(user.created_at)}</span>
                    </div>
                  </div>
                  <div className={s.pendingActions}>
                    <button onClick={() => handleApprove(user)} className={s.btnApprove}>Approve</button>
                    <button onClick={() => handleReject(user)} className={s.btnReject}>Reject</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* Users Table */}
        <div className={s.tableWrap}>
          <table className={s.table}>
            <thead>
              <tr className={s.tableHeadRow}>
                {['Username', 'Display Name', 'Role', 'Tier', 'Email', 'Status', 'Created', 'Actions'].map(h => (
                  <th key={h} className={s.th}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {loading ? (
                <tr>
                  <td colSpan={8} className={s.tdCenter}>
                    <div className={s.tdMono}>Loading users...</div>
                  </td>
                </tr>
              ) : error ? (
                <tr>
                  <td colSpan={8} className={s.tdCenterError}>
                    <div className={s.tdMono}>{typeof error === 'string' ? error : error?.message || 'An error occurred'}</div>
                    <button onClick={fetchUsers} className={`${s.btnSecondary} ${s.ml8}`} style={{ marginTop: 12 }}>Retry</button>
                  </td>
                </tr>
              ) : nonPendingUsers.length === 0 ? (
                <tr>
                  <td colSpan={8} className={s.tdCenter}>
                    <div className={s.tdMono}>No users found</div>
                  </td>
                </tr>
              ) : (
                nonPendingUsers.map(user => {
                  const userSubs = subscriptions[user.id] || {};
                  const userTier = userSubs.platform?.tier || 'free';
                  const grantedByUsername = userSubs.platform?.granted_by_username || null;

                  return (
                    <tr key={user.id} className={s.tr}>
                      {editingId === user.id ? (
                        /* ─── Inline Edit Mode ─── */
                        <>
                          <td className={s.tdEdit}>
                            <input
                              value={editData.username || user.username}
                              disabled
                              className={s.formInputDisabled}
                            />
                          </td>
                          <td className={s.tdEdit}>
                            <input
                              value={editData.display_name}
                              onChange={e => setEditData({ ...editData, display_name: e.target.value })}
                              className={s.formInput}
                            />
                          </td>
                          <td className={s.tdEdit}>
                            <select
                              value={editData.role}
                              onChange={e => setEditData({ ...editData, role: e.target.value })}
                              className={s.formSelect}
                            >
                              {ROLES.map(r => (
                                <option key={r} value={r}>{r.charAt(0).toUpperCase() + r.slice(1)}</option>
                              ))}
                            </select>
                          </td>
                          <td className={s.tdEdit}>
                            <TierBadge tier={userTier} grantedBy={grantedByUsername} />
                          </td>
                          <td className={s.tdEdit}>
                            <input
                              value={editData.email}
                              onChange={e => setEditData({ ...editData, email: e.target.value })}
                              className={s.formInput}
                            />
                          </td>
                          <td className={s.tdEdit}>
                            <select
                              value={editData.status}
                              onChange={e => setEditData({ ...editData, status: e.target.value })}
                              className={s.formSelect}
                            >
                              {Object.keys(STATUS_COLORS).map(st => (
                                <option key={st} value={st}>{st.replace('_', ' ').toUpperCase()}</option>
                              ))}
                            </select>
                          </td>
                          <td className={s.tdEdit}>{formatDate(user.created_at)}</td>
                          <td className={s.tdActions}>
                            <button onClick={() => saveEdit(user.id)} className={s.btnSuccess}>Save</button>
                            <button onClick={cancelEdit} className={`${s.btnSecondary} ${s.ml8}`}>Cancel</button>
                          </td>
                        </>
                      ) : (
                        /* ─── Display Mode ─── */
                        <>
                          <td className={s.tdUsername}>{user.username}</td>
                          <td className={s.tdDisplayName}>{user.display_name}</td>
                          <td className={s.td}><RoleBadge role={user.role} /></td>
                          <td className={s.td}><TierBadge tier={userTier} grantedBy={grantedByUsername} /></td>
                          <td className={s.tdEmail}>{user.email}</td>
                          <td className={s.td}><StatusDot status={user.status} /></td>
                          <td className={s.td}>{formatDate(user.created_at)}</td>
                          <td className={s.tdActions}>
                            <button onClick={() => startEdit(user)} className={s.btnSecondary}>Edit</button>
                            <button onClick={() => setGrantTarget(user)} className={`${s.btnSuccess} ${s.ml8}`}>Grant</button>
                            <button onClick={() => toggleStatus(user)} className={`${s.btnSecondary} ${s.ml8}`}>
                              {user.status === 'active' ? 'Deactivate' : 'Activate'}
                            </button>
                            <button onClick={() => setDeleteConfirm(user)} className={`${s.btnDanger} ${s.ml8}`}>Delete</button>
                          </td>
                        </>
                      )}
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>

        {/* Delete Confirmation */}
        {deleteConfirm && (
          <ConfirmModal
            message={`Are you sure you want to delete user "${deleteConfirm.username}"? This action cannot be undone.`}
            onConfirm={() => handleDelete(deleteConfirm)}
            onCancel={() => setDeleteConfirm(null)}
          />
        )}

        {/* Grant Access Modal */}
        {grantTarget && (
          <GrantAccessModal
            user={grantTarget}
            subs={subscriptions[grantTarget.id] || {}}
            onGrant={handleGrantAccess}
            onClose={() => setGrantTarget(null)}
          />
        )}
      </div>
    </LoadingState>
  );
}
